steps.solution:
def fetch(user_id):
    if user_id == 7:
        return (200, {"name": "maya"})
    return (404, {"error": "not found"})

def safe_fetch(user_id):
    status, body = fetch(user_id)
    if status == 200:
        return body["name"]
    return "error"

print(safe_fetch(7))
print(safe_fetch(404))
